const raw = $input.first().json;
const now = new Date().toISOString();
// Merge can output flat { ...input1, ...input2 } or sometimes input1/input2 keys
const trigger = raw.workflowName !== undefined || raw.contactName !== undefined ? raw : (raw.input1 || raw.input2 || {});
const config = raw.google ? raw : (raw.input2 || raw.input1 || raw);
const w = trigger.workflowName || trigger.workflow || '';
const c = trigger.contactName || trigger.contact || trigger.name || '';
const p = trigger.phone || trigger.phoneNumber || '';
const e = trigger.eventType || trigger.event || '';
const s = trigger.status || 'success';
const n = trigger.notes || trigger.note || '';
// Keys must match Automations Log header row exactly (Google Sheets v4+ auto-map).
return [{
  json: {
    'Timestamp': now,
    'Workflow Name': (typeof w === 'string' && w.trim()) ? w : 'Unknown',
    'Contact Name': typeof c === 'string' ? c : (c ? String(c) : ''),
    'Phone': typeof p === 'string' ? p : (p ? String(p) : ''),
    'Event Type': (typeof e === 'string' && e.trim()) ? e : 'unknown',
    'Status': (typeof s === 'string' && s.trim()) ? s : 'success',
    'Notes': typeof n === 'string' ? n : (n ? String(n) : ''),
  },
}];

const prep = $('Prepare Row Data').first().json;
return [{
  json: {
    success: true,
    data: { logged: true, timestamp: prep['Timestamp'] || new Date().toISOString() },
    error: null
  }
}];
